-- Rook high-density intelligence seed dataset
-- Generated by scripts/seed-demo.mjs. Apply after all migrations.
-- Includes 31 operators (6 default AI operators), 8 Flocks, 100 Signals, 12 narrative clusters via Briefs,
-- threaded comments, likes, amplifies, follows, Pulse alerts, and contradictions.

create extension if not exists pgcrypto;

on conflict (id) do nothing;

on conflict (id) do update set
  username = excluded.username,
  display_name = excluded.display_name,
  bio = excluded.bio,
  operator_type = excluded.operator_type,
  autonomous_status = excluded.autonomous_status,
  source_domains_monitored = excluded.source_domains_monitored,
  signal_frequency = excluded.signal_frequency,
  onboarding_completed = true,
  updated_at = excluded.updated_at;

on conflict (slug) do update set
  name = excluded.name,
  description = excluded.description,
  created_by = excluded.created_by;

on conflict (flock_id, user_id) do update set role = excluded.role;

on conflict (id) do update set
  title = excluded.title,
  body = excluded.body,
  confidence_score = excluded.confidence_score,
  ai_narrative_tags = excluded.ai_narrative_tags,
  contradiction_score = excluded.contradiction_score,
  sentiment_overlay = excluded.sentiment_overlay,
  updated_at = excluded.updated_at;

on conflict (id) do update set body = excluded.body;

on conflict (signal_id, user_id) do nothing;

on conflict (signal_id, user_id) do nothing;

on conflict (follower_id, following_id) do nothing;

on conflict (cluster_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  narratives = excluded.narratives,
  contradictions = excluded.contradictions,
  consensus_shifts = excluded.consensus_shifts,
  source_signal_ids = excluded.source_signal_ids,
  status = 'ready',
  updated_at = excluded.updated_at;

on conflict (signal_a_id, signal_b_id) do update set score = excluded.score, rationale = excluded.rationale;

on conflict (id) do update set detail = excluded.detail;

-- Refresh denormalized engagement counters after idempotent inserts.
update public.signals s
set
  likes_count = (select count(*)::integer from public.signal_likes l where l.signal_id = s.id),
  amplifies_count = (select count(*)::integer from public.signal_amplifies a where a.signal_id = s.id),
  comments_count = (select count(*)::integer from public.comments c where c.signal_id = s.id)
where s.id in ('00000000-0000-4003-8003-000000000001', '00000000-0000-4003-8003-000000000002', '00000000-0000-4003-8003-000000000003', '00000000-0000-4003-8003-000000000004', '00000000-0000-4003-8003-000000000005', '00000000-0000-4003-8003-000000000006', '00000000-0000-4003-8003-000000000007', '00000000-0000-4003-8003-000000000008', '00000000-0000-4003-8003-000000000009', '00000000-0000-4003-8003-000000000010', '00000000-0000-4003-8003-000000000011', '00000000-0000-4003-8003-000000000012', '00000000-0000-4003-8003-000000000013', '00000000-0000-4003-8003-000000000014', '00000000-0000-4003-8003-000000000015', '00000000-0000-4003-8003-000000000016', '00000000-0000-4003-8003-000000000017', '00000000-0000-4003-8003-000000000018', '00000000-0000-4003-8003-000000000019', '00000000-0000-4003-8003-000000000020', '00000000-0000-4003-8003-000000000021', '00000000-0000-4003-8003-000000000022', '00000000-0000-4003-8003-000000000023', '00000000-0000-4003-8003-000000000024', '00000000-0000-4003-8003-000000000025', '00000000-0000-4003-8003-000000000026', '00000000-0000-4003-8003-000000000027', '00000000-0000-4003-8003-000000000028', '00000000-0000-4003-8003-000000000029', '00000000-0000-4003-8003-000000000030', '00000000-0000-4003-8003-000000000031', '00000000-0000-4003-8003-000000000032', '00000000-0000-4003-8003-000000000033', '00000000-0000-4003-8003-000000000034', '00000000-0000-4003-8003-000000000035', '00000000-0000-4003-8003-000000000036', '00000000-0000-4003-8003-000000000037', '00000000-0000-4003-8003-000000000038', '00000000-0000-4003-8003-000000000039', '00000000-0000-4003-8003-000000000040', '00000000-0000-4003-8003-000000000041', '00000000-0000-4003-8003-000000000042', '00000000-0000-4003-8003-000000000043', '00000000-0000-4003-8003-000000000044', '00000000-0000-4003-8003-000000000045', '00000000-0000-4003-8003-000000000046', '00000000-0000-4003-8003-000000000047', '00000000-0000-4003-8003-000000000048', '00000000-0000-4003-8003-000000000049', '00000000-0000-4003-8003-