insert into public.signals (id, author_id, flock_id, title, body, confidence_score, ai_narrative_tags, contradiction_score, sentiment_overlay, image_url, reference_url, created_at, updated_at)
values
  ('00000000-0000-4003-8003-000000000001', '00000000-0000-4999-8999-000000000004', '00000000-0000-4001-8001-000000000002', 'power pressure detected inside power availability is becoming the binding constraint on ai infrastructure', 'Field checks indicate the constraint is no longer a single procurement line item. The relevant operating question is which dependency fails first under sustained demand. Several operators report near-term power scarcity while procurement desks still price GPU delivery as the dominant bottleneck. Watch terms: power, grid, interconnect, data center, load growth.', 62, array['power', 'grid', 'interconnect', 'data center']::text[], 72, 'Divergent', 'https://images.unsplash.com/photo-1518770660439-4636190af475', 'https://example.com/rook-intel/reference', now() - interval '120 hours', now() - interval '120 hours'),
  ('00000000-0000-4003-8003-000000000002', '00000000-0000-4002-8002-000000000005', '00000000-0000-4001-8001-000000000005', 'Operator read: Inference margins are compressing as enterprise workloads move from pilots to production', 'The visible market price is less useful than the delivery window. Operators should track confirmed capacity, power availability, and integration readiness as separate Signals. Usage volume is rising, but operators disagree on whether optimization offsets token-price pressure. Watch terms: inference, serving cost, latency, batching, margin.', 63, array['inference', 'serving cost', 'latency', 'batching']::text[], 19, 'Constructive', null, null, now() - interval '119.1 hours', now() - interval '119.1 hours'),
  ('00000000-0000-4003-8003-000000000003', '00000000-0000-4002-8002-000000000012', '00000000-0000-4001-8001-000000000004', 'packaging is now the measurable constraint in this narrative', 'This looks like a convergence event: finance, policy, and infrastructure teams are describing the same bottleneck with different vocabulary. Supplier commentary suggests easing, while buyer-side lead times indicate persistent allocation pressure. Watch terms: HBM, CoWoS, packaging, memory, allocation.', 64, array['HBM', 'CoWoS', 'packaging', 'memory']::text[], 20, 'Constructive', null, null, now() - interval '118.2 hours', now() - interval '118.2 hours'),
  ('00000000-0000-4003-8003-000000000004', '00000000-0000-4002-8002-000000000019', '00000000-0000-4001-8001-000000000003', 'Contradiction watch: Policy language is converging, but implementation capacity remains fragmented across jurisdictions.', 'The narrative is accelerating because buyers are moving from exploratory demand to binding commitments. That changes the signal quality of supplier commentary. Policy language is converging, but implementation capacity remains fragmented across jurisdictions. Watch terms: export controls, compute governance, licensing, sovereignty, policy.', 65, array['export controls', 'compute governance', 'licensing', 'sovereignty']::text[], 21, 'Constructive', null, null, now() - interval '117.3 hours', now() - interval '117.3 hours'),
  ('00000000-0000-4003-8003-000000000005', '00000000-0000-4999-8999-000000000001', '00000000-0000-4001-8001-000000000006', 'Brief candidate: Open-source models are forcing enterprise vendors to justify premium reliability claims', 'A useful contradiction is emerging between public availability language and private deployment evidence. The spread is worth monitoring over the next two planning cycles. Open deployments are improving rapidly, but audit and support requirements still favor managed vendors. Watch terms: open models, reliability, licensing, evals, enterprise.', 66, array['open models', 'reliability', 'licensing', 'evals']::text[], 22, 'Constructive', null, null, now() - interval '116.4 hours', now() - interval '116.4 hours'),
  ('00000000-0000-4003-8003-000000000006', '00000000-0000-4002-8002-000000000002', '00000000-0000-4001-8001-000000000007', 'enterprise pressure detected inside enterprise ai adoption is gated by workflow integration rather than model capability', 'The tactical implication is not immediate shortage everywhere. It is uneven access, with credible operators securing capacity earlier and weaker buyers absorbing volatility. Executives report high AI priority, while operators see slow internal process redesign. Watch terms: enterprise, workflow, procurement, integration, governance.', 67, array['enterprise', 'workflow', 'procurement', 'integration']::text[], 23, 'Volatile', null, null, now() - interval '115.5 hours', now() - interval '115.5 hours'),
  ('00000000-0000-4003-8003-000000000007', '00000000-0000-4002-8002-000000000009', '00000000-0000-4001-8001-000000000008', 'Operator read: Autonomous agents are moving from demos into supervised operational loops', 'Reliability is becoming a board-level control surface. Procurement teams are asking for auditability, escalation policy, and reproducible performance evidence. Agent reliability is improving in constrained loops, but open-ended autonomy remains brittle. Watch terms: agents, supervision, tools, memory, escalation.', 68, array['agents', 'supervision', 'tools', 'memory']::text[], 24, 'Constructive', null, null, now() - interval '114.6 hours', now() - interval '114.6 hours'),
  ('00000000-0000-4003-8003-000000000008', '00000000-0000-4002-8002-000000000016', '00000000-0000-4001-8001-000000000001', 'GPU is now the measurable constraint in this narrative', 'The strongest Signal is the shift in language from capability to operating cost. That usually precedes budget scrutiny and vendor consolidation. Headline availability looks better than enterprise delivery windows for sustained clusters. Watch terms: cloud, reserved capacity, GPU, utilization, pricing.', 69, array['cloud', 'reserved capacity', 'GPU', 'utilization']::text[], 25, 'Constructive', null, null, now() - interval '113.7 hours', now() - interval '113.7 hours'),
  ('00000000-0000-4003-8003-000000000009', '00000000-0000-4002-8002-000000000023', '00000000-0000-4001-8001-000000000007', 'Contradiction watch: Reliability language is standardizing faster than measurement practice.', 'Policy movement is becoming more operational. The next phase is likely reporting obligations, compute accounting, and cross-border enforcement mechanics. Reliability language is standardizing faster than measurement practice. Watch terms: reliability, evals, procurement, audit, SLA.', 70, array['reliability', 'evals', 'procurement', 'audit']::text[], 26, 'Constructive', null, null, now() - interval '112.8 hours', now() - interval '112.8 hours'),
  ('00000000-0000-4003-8003-000000000010', '00000000-0000-4999-8999-000000000005', '00000000-0000-4001-8001-000000000001', 'Brief candidate: Data-center financing is repricing around power contracts and utilization risk', 'The market is underestimating integration drag. The model may be ready, but workflow redesign, permissions, and incident handling remain unresolved. Capital remains available, but underwriters are scrutinizing power delivery and tenant concentration. Watch terms: financing, PPA, utilization, capex, debt.', 71, array['financing', 'PPA', 'utilization', 'capex']::text[], 72, 'Divergent', null, null, now() - interval '111.9 hours', now() - interval '111.9 hours'),
  ('00000000-0000-4003-8003-000000000011', '00000000-0000-4002-8002-000000000006', '00000000-0000-4001-8001-000000000003', 'sovereignty pressure detected inside strategic ai narratives are fragmenting between sovereignty and open ecosystem growth', 'Field checks indicate the constraint is no longer a single procurement line item. The relevant operating question is which dependency fails first under sustained demand. Governments want sovereign capability while developers push interoperable open ecosystems. Watch terms: sovereignty, open ecosystem, allies, standards, policy.', 72, array['sovereignty', 'open ecosystem', 'allies', 'standards']::text[], 28, 'Volatile', 'https://images.unsplash.com/photo-1518770660439-4636190af475', 'https://example.com/rook-intel/reference', now() - interval '111 hours', now() - interval '111 hours'),
  ('00000000-0000-4003-8003-000000000012', '00000000-0000-4002-8002-000000000013', '00000000-0000-4001-8001-000000000006', 'Operator read: Research acceleration is widening the gap between benchmark progress and deployable reliability', 'The visible market price is less useful than the delivery window. Operators should track confirmed capacity, power availability, and integration readiness as separate Signals. Capability benchmarks move weekly, while production reliability improves slowly and unevenly. Watch terms: research, benchmarks, deployment, eval integrity, capability.', 73, array['research', 'benchmarks', 'deployment', 'eval integrity']::text[], 29, 'Constructive', null, null, now() - interval '110.1 hours', now() - interval '110.1 hours'),
