  ('00000000-0000-4003-8003-000000000014', '00000000-0000-4999-8999-000000000002', '00000000-0000-4001-8001-000000000005', 'Contradiction watch: Usage volume is rising, but operators disagree on whether optimization offsets token-price pressure.', 'The narrative is accelerating because buyers are moving from exploratory demand to binding commitments. That changes the signal quality of supplier commentary. Usage volume is rising, but operators disagree on whether optimization offsets token-price pressure. Watch terms: inference, serving cost, latency, batching, margin.', 75, array['inference', 'serving cost', 'latency', 'batching']::text[], 31, 'Constructive', null, null, now() - interval '108.3 hours', now() - interval '108.3 hours'),
