values
  ('00000000-0000-4005-8005-000000000001', 'Power availability is becoming the binding constraint on AI infrastructure', 'grid-interconnect-power', 'Executive read: Power availability is becoming the binding constraint on AI infrastructure. The cluster shows several operators report near-term power scarcity while procurement desks still price gpu delivery as the dominant bottleneck. Operators should monitor power, grid, interconnect for the next acceleration moment.', array['power', 'grid', 'interconnect', 'data center']::text[], array['Several operators report near-term power scarcity while procurement desks still price GPU delivery as the dominant bottleneck.']::text[], array['Consensus is forming around power as the primary watch variable.']::text[], 'Sentiment is fragmenting around implementation risk.', 'Primary activity is concentrated in Critical Infrastructure.', array['00000000-0000-4003-8003-000000000001'::uuid, '00000000-0000-4003-8003-000000000013'::uuid, '00000000-0000-4003-8003-000000000025'::uuid, '00000000-0000-4003-8003-000000000037'::uuid, '00000000-0000-4003-8003-000000000049'::uuid, '00000000-0000-4003-8003-000000000061'::uuid, '00000000-0000-4003-8003-000000000073'::uuid, '00000000-0000-4003-8003-000000000085'::uuid]::uuid[], 'ready', '00000000-0000-4999-8999-000000000001', now() - interval '24 hours', now() - interval '24 hours', now() - interval '24 hours'),
  ('00000000-0000-4005-8005-000000000002', 'Inference margins are compressing as enterprise workloads move from pilots to production', 'inference-latency-serving cost', 'Executive read: Inference margins are compressing as enterprise workloads move from pilots to production. The cluster shows usage volume is rising, but operators disagree on whether optimization offsets token-price pressure. Operators should monitor inference, serving cost, latency for the next acceleration moment.', array['inference', 'serving cost', 'latency', 'batching']::text[], array['Usage volume is rising, but operators disagree on whether optimization offsets token-price pressure.']::text[], array['Consensus is forming around inference as the primary watch variable.']::text[], 'Sentiment is converging around operational constraints.', 'Primary activity is concentrated in Inference Economics.', array['00000000-0000-4003-8003-000000000002'::uuid, '00000000-0000-4003-8003-000000000014'::uuid, '00000000-0000-4003-8003-000000000026'::uuid, '00000000-0000-4003-8003-000000000038'::uuid, '00000000-0000-4003-8003-000000000050'::uuid, '00000000-0000-4003-8003-000000000062'::uuid, '00000000-0000-4003-8003-000000000074'::uuid, '00000000-0000-4003-8003-000000000086'::uuid]::uuid[], 'ready', '00000000-0000-4999-8999-000000000002', now() - interval '23 hours', now() - interval '23 hours', now() - interval '23 hours'),
  ('00000000-0000-4005-8005-000000000003', 'HBM and advanced packaging remain the hidden governor on accelerator supply', 'CoWoS-HBM-packaging', 'Executive read: HBM and advanced packaging remain the hidden governor on accelerator supply. The cluster shows supplier commentary suggests easing, while buyer-side lead times indicate persistent allocation pressure. Operators should monitor HBM, CoWoS, packaging for the next acceleration moment.', array['HBM', 'CoWoS', 'packaging', 'memory']::text[], array['Supplier commentary suggests easing, while buyer-side lead times indicate persistent allocation pressure.']::text[], array['Consensus is forming around HBM as the primary watch variable.']::text[], 'Sentiment is converging around operational constraints.', 'Primary activity is concentrated in Compute Supply Chain.', array['00000000-0000-4003-8003-000000000003'::uuid, '00000000-0000-4003-8003-000000000015'::uuid, '00000000-0000-4003-8003-000000000027'::uuid, '00000000-0000-4003-8003-000000000039'::uuid, '00000000-0000-4003-8003-000000000051'::uuid, '00000000-0000-4003-8003-000000000063'::uuid, '00000000-0000-4003-8003-000000000075'::uuid, '00000000-0000-4003-8003-000000000087'::uuid]::uuid[], 'ready', '00000000-0000-4999-8999-000000000003', now() - interval '22 hours', now() - interval '22 hours', now() - interval '22 hours'),
  ('00000000-0000-4005-8005-000000000004', 'AI export controls are shifting from chip lists toward compute governance', 'compute governance-export controls-licensing', 'Executive read: AI export controls are shifting from chip lists toward compute governance. The cluster shows policy language is converging, but implementation capacity remains fragmented across jurisdictions. Operators should monitor export controls, compute governance, licensing for the next acceleration moment.', array['export controls', 'compute governance', 'licensing', 'sovereignty']::text[], array['Policy language is converging, but implementation capacity remains fragmented across jurisdictions.']::text[], array['Consensus is forming around export controls as the primary watch variable.']::text[], 'Sentiment is fragmenting around implementation risk.', 'Primary activity is concentrated in AI Policy Watch.', array['00000000-0000-4003-8003-000000000004'::uuid, '00000000-0000-4003-8003-000000000016'::uuid, '00000000-0000-4003-8003-000000000028'::uuid, '00000000-0000-4003-8003-000000000040'::uuid, '00000000-0000-4003-8003-000000000052'::uuid, '00000000-0000-4003-8003-000000000064'::uuid, '00000000-0000-4003-8003-000000000076'::uuid, '00000000-0000-4003-8003-000000000088'::uuid]::uuid[], 'ready', '00000000-0000-4999-8999-000000000004', now() - interval '21 hours', now() - interval '21 hours', now() - interval '21 hours'),
  ('00000000-0000-4005-8005-000000000005', 'Open-source models are forcing enterprise vendors to justify premium reliability claims', 'licensing-open models-reliability', 'Executive read: Open-source models are forcing enterprise vendors to justify premium reliability claims. The cluster shows open deployments are improving rapidly, but audit and support requirements still favor managed vendors. Operators should monitor open models, reliability, licensing for the next acceleration moment.', array['open models', 'reliability', 'licensing', 'evals']::text[], array['Open deployments are improving rapidly, but audit and support requirements still favor managed vendors.']::text[], array['Consensus is forming around open models as the primary watch variable.']::text[], 'Sentiment is converging around operational constraints.', 'Primary activity is concentrated in Open Model Analysis.', array['00000000-0000-4003-8003-000000000005'::uuid, '00000000-0000-4003-8003-000000000017'::uuid, '00000000-0000-4003-8003-000000000029'::uuid, '00000000-0000-4003-8003-000000000041'::uuid, '00000000-0000-4003-8003-000000000053'::uuid, '00000000-0000-4003-8003-000000000065'::uuid, '00000000-0000-4003-8003-000000000077'::uuid, '00000000-0000-4003-8003-000000000089'::uuid]::uuid[], 'ready', '00000000-0000-4999-8999-000000000005', now() - interval '20 hours', now() - interval '20 hours', now() - interval '20 hours'),
  ('00000000-0000-4005-8005-000000000006', 'Enterprise AI adoption is gated by workflow integration rather than model capability', 'enterprise-procurement-workflow', 'Executive read: Enterprise AI adoption is gated by workflow integration rather than model capability. The cluster shows executives report high ai priority, while operators see slow internal process redesign. Operators should monitor enterprise, workflow, procurement for the next acceleration moment.', array['enterprise', 'workflow', 'procurement', 'integration']::text[], array['Executives report high AI priority, while operators see slow internal process redesign.']::text[], array['Consensus is forming around enterprise as the primary watch variable.']::text[], 'Sentiment is converging around operational constraints.', 'Primary activity is concentrated in Enterprise Adoption.', array['00000000-0000-4003-8003-000000000006'::uuid, '00000000-0000-4003-8003-000000000018'::uuid, '00000000-0000-4003-8003-000000000030'::uuid, '00000000-0000-4003-8003-000000000042'::uuid, '00000000-0000-4003-8003-000000000054'::uuid, '00000000-0000-4003-8003-000000000066'::uuid, '00000000-0000-4003-8003-000000000078'::uuid, '00000000-0000-4003-8003-000000000090'::uuid]::uuid[], 'ready', '00000000-0000-4999-8999-000000000006', now() - interval '19 hours', now() - interval '19 hours', now() - interval '19 hours'),
  ('00000000-0000-4005-8005-000000000007', 'Autonomous agents are moving from demos into supervised operational loops', 'agents-supervision-tools', 'Executive read: Autonomous agents are moving from demos into supervised operational loops. The cluster shows agent reliability is improving in constrained loops, but open-ended autonomy remains brittle. Operators should monitor agents, supervision, tools for the next acceleration moment.', array['agents', 'supervision', 'tools', 'memory']::text[], array['Agent reliability is improving in constrained loops, but open-ended autonomy remains brittle.']::text[], array['Consensus is forming around agents as the primary watch variable.']::text[], 'Sentiment is fragmenting around implementation risk.', 'Primary activity is concentrated in Autonomous Systems.', array['00000000-0000-4003-8003-000000000007'::uuid, '00000000-0000-4003-8003-000000000019'::uuid, '00000000-0000-4003-8003-000000000031'::uuid, '00000000-0000-4003-8003-000000000043'::uuid, '00000000-0000-4003-8003-000000000055'::uuid, '00000000-0000-4003-8003-000000000067'::uuid, '00000000-0000-4003-8003-000000000079'::uuid, '00000000-0000-4003-8003-000000000091'::uuid]::uuid[], 'ready', '00000000-0000-4002-8002-000000000001', now() - interval '18 hours', now() - interval '18 hours', now() - interval '18 hours'),
  ('00000000-0000-4005-8005-000000000008', 'Cloud reserved capacity is masking true accelerator scarcity', 'GPU-cloud-reserved capacity', 'Executive read: Cloud reserved capacity is masking true accelerator scarcity. The cluster shows headline availability looks better than enterprise delivery windows for sustained clusters. Operators should monitor cloud, reserved capacity, GPU for the next acceleration moment.', array['cloud', 'reserved capacity', 'GPU', 'utilization']::text[], array['Headline availability looks better than enterprise delivery windows for sustained clusters.']::text[], array['Consensus is forming around cloud as the primary watch variable.']::text[], 'Sentiment is converging around operational constraints.', 'Primary activity is concentrated in AI Markets.', array['00000000-0000-4003-8003-000000000008'::uuid, '00000000-0000-4003-8003-000000000020'::uuid, '00000000-0000-4003-8003-000000000032'::uuid, '00000000-0000-4003-8003-000000000044'::uuid, '00000000-0000-4003-8003-000000000056'::uuid, '00000000-0000-4003-8003-000000000068'::uuid, '00000000-0000-4003-8003-000000000080'::uuid, '00000000-0000-4003-8003-000000000092'::uuid]::uuid[], 'ready', '00000000-0000-4002-8002-000000000002', now() - interval '17 hours', now() - interval '17 hours', now() - interval '17 hours'),
  ('00000000-0000-4005-8005-000000000009', 'Model reliability is becoming a procurement requirement, not an engineering preference', 'evals-procurement-reliability', 'Executive read: Model reliability is becoming a procurement requirement, not an engineering preference. The cluster shows reliability language is standardizing faster than measurement practice. Operators should monitor reliability, evals, procurement for the next acceleration moment.', array['reliability', 'evals', 'procurement', 'audit']::text[], array['Reliability language is standardizing faster than measurement practice.']::text[], array['Consensus is forming around reliability as the primary watch variable.']::text[], 'Sentiment is converging around operational constraints.', 'Primary activity is concentrated in Enterprise Adoption.', array['00000000-0000-4003-8003-000000000009'::uuid, '00000000-0000-4003-8003-000000000021'::uuid, '00000000-0000-4003-8003-000000000033'::uuid, '00000000-0000-4003-8003-000000000045'::uuid, '00000000-0000-4003-8003-000000000057'::uuid, '00000000-0000-4003-8003-000000000069'::uuid, '00000000-0000-4003-8003-000000000081'::uuid, '00000000-0000-4003-8003-000000000093'::uuid]::uuid[], 'ready', '00000000-0000-4002-8002-000000000003', now() - interval '16 hours', now() - interval '16 hours', now() - interval '16 hours'),
  ('00000000-0000-4005-8005-000000000010', 'Data-center financing is repricing around power contracts and utilization risk', 'PPA-financing-utilization', 'Executive read: Data-center financing is repricing around power contracts and utilization risk. The cluster shows capital remains available, but underwriters are scrutinizing power delivery and tenant concentration. Operators should monitor financing, PPA, utilization for the next acceleration moment.', array['financing', 'PPA', 'utilization', 'capex']::text[], array['Capital remains available, but underwriters are scrutinizing power delivery and tenant concentration.']::text[], array['Consensus is forming around financing as the primary watch variable.']::text[], 'Sentiment is fragmenting around implementation risk.', 'Primary activity is concentrated in AI Markets.', array['00000000-0000-4003-8003-000000000010'::uuid, '00000000-0000-4003-8003-000000000022'::uuid, '00000000-0000-4003-8003-000000000034'::uuid, '00000000-0000-4003-8003-000000000046'::uuid, '00000000-0000-4003-8003-000000000058'::uuid, '00000000-0000-4003-8003-000000000070'::uuid, '00000000-0000-4003-8003-000000000082'::uuid, '00000000-0000-4003-8003-000000000094'::uuid]::uuid[], 'ready', '00000000-0000-4002-8002-000000000004', now() - interval '15 hours', now() - interval '15 hours', now() - interval '15 hours'),
  ('00000000-0000-4005-8005-000000000011', 'Strategic AI narratives are fragmenting between sovereignty and open ecosystem growth', 'allies-open ecosystem-sovereignty', 'Executive read: Strategic AI narratives are fragmenting between sovereignty and open ecosystem growth. The cluster shows governments want sovereign capability while developers push interoperable open ecosystems. Operators should monitor sovereignty, open ecosystem, allies for the next acceleration moment.', array['sovereignty', 'open ecosystem', 'allies', 'standards']::text[], array['Governments want sovereign capability while developers push interoperable open ecosystems.']::text[], array['Consensus is forming around sovereignty as the primary watch variable.']::text[], 'Sentiment is converging around operational constraints.', 'Primary activity is concentrated in AI Policy Watch.', array['00000000-0000-4003-8003-000000000011'::uuid, '00000000-0000-4003-8003-000000000023'::uuid, '00000000-0000-4003-8003-000000000035'::uuid, '00000000-0000-4003-8003-000000000047'::uuid, '00000000-0000-4003-8003-000000000059'::uuid, '00000000-0000-4003-8003-000000000071'::uuid, '00000000-0000-4003-8003-000000000083'::uuid, '00000000-0000-4003-8003-000000000095'::uuid]::uuid[], 'ready', '00000000-0000-4002-8002-000000000005', now() - interval '14 hours', now() - interval '14 hours', now() - interval '14 hours'),
  ('00000000-0000-4005-8005-000000000012', 'Research acceleration is widening the gap between benchmark progress and deployable reliability', 'benchmarks-deployment-research', 'Executive read: Research acceleration is widening the gap between benchmark progress and deployable reliability. The cluster shows capability benchmarks move weekly, while production reliability improves slowly and unevenly. Operators should monitor research, benchmarks, deployment for the next acceleration moment.', array['research', 'benchmarks', 'deployment', 'eval integrity']::text[], array['Capability benchmarks move weekly, while production reliability improves slowly and unevenly.']::text[], array['Consensus is forming around research as the primary watch variable.']::text[], 'Sentiment is converging around operational constraints.', 'Primary activity is concentrated in Open Model Analysis.', array['00000000-0000-4003-8003-000000000012'::uuid, '00000000-0000-4003-8003-000000000024'::uuid, '00000000-0000-4003-8003-000000000036'::uuid, '00000000-0000-4003-8003-000000000048'::uuid, '00000000-0000-4003-8003-000000000060'::uuid, '00000000-0000-4003-8003-000000000072'::uuid, '00000000-0000-4003-8003-000000000084'::uuid, '00000000-0000-4003-8003-000000000096'::uuid]::uuid[], 'ready', '00000000-0000-4002-8002-000000000006', now() - interval '13 hours', now() - interval '13 hours', now() - interval '13 hours')
